import{_ as s,o as e,c as n,ag as i}from"./chunks/framework.DL0AyVxm.js";const u=JSON.parse('{"title":"Upgrading","description":"","frontmatter":{},"headers":[],"relativePath":"guide/upgrading.md","filePath":"guide/upgrading.md"}'),t={name:"guide/upgrading.md"};function p(l,a,o,r,d,c){return e(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="upgrading" tabindex="-1">Upgrading <a class="header-anchor" href="#upgrading" aria-label="Permalink to &quot;Upgrading&quot;">​</a></h1><p>When a new version of Worclaude is released, you can update your project&#39;s workflow files without losing your customizations. This page covers Scenario C: upgrading a project that was previously set up with Worclaude.</p><h2 id="when-to-upgrade" tabindex="-1">When to Upgrade <a class="header-anchor" href="#when-to-upgrade" aria-label="Permalink to &quot;When to Upgrade&quot;">​</a></h2><p>First, update the Worclaude CLI itself:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worclaude@latest</span></span></code></pre></div><p>Then check if your project has available updates:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">worclaude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> diff</span></span></code></pre></div><p>This compares your current setup against the latest workflow version and shows what has changed:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  Comparing current setup to workflow v1.1.0:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Modified (your changes):</span></span>
<span class="line"><span>  ~ CLAUDE.md (added 5 gotchas)</span></span>
<span class="line"><span>  ~ .claude/skills/testing.md (added pytest patterns)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Missing (removed or never installed):</span></span>
<span class="line"><span>  - .claude/agents/doc-writer.md</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Extra (you added):</span></span>
<span class="line"><span>  + .claude/skills/my-custom-skill.md</span></span>
<span class="line"><span>  + .claude/agents/my-custom-agent.md</span></span></code></pre></div><p>This is a read-only command -- it does not change anything. Use it to decide whether an upgrade is worth doing.</p><h2 id="running-the-upgrade" tabindex="-1">Running the Upgrade <a class="header-anchor" href="#running-the-upgrade" aria-label="Permalink to &quot;Running the Upgrade&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">worclaude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span></span></code></pre></div><p>Worclaude reads your <code>.claude/workflow-meta.json</code> to understand what was originally installed and what version you are on:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  Worclaude Upgrade</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Current version: 1.0.0</span></span>
<span class="line"><span>  New version:     1.1.0</span></span></code></pre></div><p>If you are already on the latest version, Worclaude tells you and exits.</p><h2 id="how-change-detection-works" tabindex="-1">How Change Detection Works <a class="header-anchor" href="#how-change-detection-works" aria-label="Permalink to &quot;How Change Detection Works&quot;">​</a></h2><p>Worclaude uses SHA-256 hashes stored in <code>workflow-meta.json</code> to categorize every file into one of five groups:</p><ol><li><strong>Auto-update</strong> -- Files you have not modified since installation. These are safe to update automatically because you have not customized them.</li><li><strong>Conflict</strong> -- Files you have customized AND the workflow has updated. These need your review.</li><li><strong>New files</strong> -- Files that did not exist in the previous version. These are added directly.</li><li><strong>Unchanged</strong> -- Files where neither you nor the workflow made changes. Nothing to do.</li><li><strong>Modified</strong> -- Files you customized but the workflow has not updated. Your changes are preserved as-is.</li></ol><p>The preview shows all five categories before anything is written:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  Changes:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Auto-update (unchanged since install):</span></span>
<span class="line"><span>    ✓ agents/plan-reviewer.md</span></span>
<span class="line"><span>    ✓ agents/code-simplifier.md</span></span>
<span class="line"><span>    ✓ 12 more files</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Needs review (you&#39;ve customized these):</span></span>
<span class="line"><span>    ~ skills/context-management.md (modified since install)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  New in this version:</span></span>
<span class="line"><span>    + agents/incident-responder.md</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Unchanged (no updates needed): 8 files</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Your customizations (no workflow updates available):</span></span>
<span class="line"><span>    ~ skills/testing.md</span></span>
<span class="line"><span></span></span>
<span class="line"><span>? Proceed with upgrade? (Y/n)</span></span></code></pre></div><h2 id="what-happens-during-the-upgrade" tabindex="-1">What Happens During the Upgrade <a class="header-anchor" href="#what-happens-during-the-upgrade" aria-label="Permalink to &quot;What Happens During the Upgrade&quot;">​</a></h2><p>After you confirm, Worclaude:</p><ol><li><strong>Creates a backup</strong> of your entire Claude Code setup (same timestamped backup as Scenario B).</li><li><strong>Auto-updates</strong> files you have not touched -- replaces them with the new version directly.</li><li><strong>Saves conflict files</strong> as <code>.workflow-ref.md</code> alongside your customized versions, so you can review and merge at your own pace.</li><li><strong>Adds new files</strong> directly to your <code>.claude/</code> directory.</li><li><strong>Merges settings.json</strong> -- appends any new permissions and hooks using the same tiered logic as the initial merge (new permissions are appended, hook conflicts are prompted).</li><li><strong>Updates workflow-meta.json</strong> with the new version number, timestamp, and recomputed file hashes.</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  Upgrade complete! (1.0.0 → 1.1.0)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Updated:     14 files</span></span>
<span class="line"><span>  Conflicts:   1 files (saved as .workflow-ref.md)</span></span>
<span class="line"><span>  New:         1 files added</span></span>
<span class="line"><span>  Unchanged:   8 files</span></span>
<span class="line"><span>  Customized:  2 files (no updates needed)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Backup: .claude-backup-20260325-091500/</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Review .workflow-ref.md files and merge what&#39;s useful.</span></span></code></pre></div><h2 id="handling-conflict-files" tabindex="-1">Handling Conflict Files <a class="header-anchor" href="#handling-conflict-files" aria-label="Permalink to &quot;Handling Conflict Files&quot;">​</a></h2><p>After the upgrade, review any <code>.workflow-ref.md</code> files the same way you would after a Scenario B merge. Open the reference file alongside your customized version, merge what is useful, and delete the reference file when you are done.</p><p>See <a href="/Worclaude/guide/existing-projects.html">Existing Projects</a> for detailed guidance on reviewing <code>.workflow-ref.md</code> files.</p><h2 id="restoring-after-a-failed-upgrade" tabindex="-1">Restoring After a Failed Upgrade <a class="header-anchor" href="#restoring-after-a-failed-upgrade" aria-label="Permalink to &quot;Restoring After a Failed Upgrade&quot;">​</a></h2><p>If something goes wrong, restore from the backup:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">worclaude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restore</span></span></code></pre></div><p>Select the backup that was created during the upgrade and your setup will be restored to its pre-upgrade state.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/Worclaude/guide/workflow-tips.html">Workflow Tips</a> -- Best practices for working with Claude Code</li><li><a href="/Worclaude/guide/existing-projects.html">Existing Projects</a> -- How the merge system works in detail</li><li><a href="/Worclaude/guide/getting-started.html">Getting Started</a> -- Full setup walkthrough for new projects</li></ul>`,33)])])}const g=s(t,[["render",p]]);export{u as __pageData,g as default};
